INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-08170', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '一般而言，團體成員在結束階段會伴隨強烈的情緒反應，團體領導者必須做妥適處理。但下列團體何者除 外？', '["教育性團體", "成長性團體", "支持性團體", "治療性團體"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08171', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '工作者在計劃組織團體時，有三方面主要因素需加以考量，下列何者除外？', '["個別成員的動機和期待", "團體的環境因素（機構組織、社區和社會因素）", "工作者本身的目的", "團體本身的目的"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08172', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於團體中的非自願或抗拒的成員，工作者比較不適宜的作為是：', '["認知成員是有權利拒絕參加的", "不必太在意他們的行為，以免影響團體氣氛", "發展非批判、接納的和安全的團體環境", "澄清成員的權利和選擇的範圍"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08173', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '為了協助成員瞭解成員的互動如何影響到整個團體，一個精神病患家屬支持團體的領導者，經常從團體討 論中跳出來，將當時的團體現象做描述，此一技巧是：', '["面質的技巧", "分析的技巧", "此時此地（here-and-now）的技巧", "綜合的技巧"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08174', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作有其特定的目標，但並不在於：', '["實質解決社區問題", "改變社區民眾個人行為或提昇其社會心理功能", "提昇社區人民的自治與行動能力", "滿足社區需求"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08175', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '由於社會變遷的多元複雜性，有些社區已超越了地理空間的架構，例如棒球迷組成的「王健民俱樂部」應 屬於何種類型社區？', '["地理社區", "信仰社區", "利益社區", "組織社區"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08176', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在某個社會工作研究中，「家庭功能」這個變項：', '["只可以成為自變項", "只可以成為依變項", "只可以成為控制變項", "成為何種變項應視研究假設而定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08177', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '社會工作研究可能會出現專業倫理與研究倫理衝突的兩難情況，例如：研究訪談過程得知有兒童正處受虐 危害，或回應者正嚴重地傷害自己或家人，以至處於立即性危險中。面臨上述情形，下列何者是不當的處 理？', '["因為是在進行研究，保密性的研究倫理勝於工作專業倫理", "專業倫理考量為先，向適當機構通告，以便採取救援介入，可能中斷該案之研究", "研究對象的告知同意中，應告知會有中斷研究的各種可能性", "此為案例並非通則，個案或家人遭遇危險的程度和立即性，會影響倫理兩難的知覺程度及處理的方法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08178', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在扎根理論（grounded theory）中，研究者就初步的資料檢視，可能提出一般性的假設，繼而研究者會去尋 找資料中違反最初假設的所有個案，評估這些個案的結果後，決定要放棄原先假設或部分修改假設。下列 何者對於這樣的質性分析過程是不正確的說法？', '["它是一種分析性歸納", "它是歸納推理", "它超越描述，尋找變項間的模式和關係", "它是質性假設檢定的技術"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08179', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關調查研究法特性的敘述，何者不正確？', '["調查研究法特別適合大規模樣本的描述性目的", "調查研究法可適用在解釋性的目的", "調查研究法可全面地呈現人們在自然環境中的歷程", "調查研究法在資料蒐集上有標準化的優點"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
